package main

type TreeNode struct {
    Value int
    Left  *TreeNode
    Right *TreeNode
}

func lowestCommonAncestorOfABst(root, p, q *TreeNode) *TreeNode {
    pathP := []*TreeNode{}
    pathQ := []*TreeNode{}

    findPath(root, p, &pathP)
    findPath(root, q, &pathQ)

    var lca *TreeNode
    for i := 0; i < len(pathP) && i < len(pathQ); i++ {
        if pathP[i] == pathQ[i] {
            lca = pathP[i]
        } else {
            break
        }
    }
    return lca
}

func findPath(root, target *TreeNode, path *[]*TreeNode) bool {
    if root == nil {
        return false
    }
    *path = append(*path, root)

    if root == target {
        return true
    }

    if findPath(root.Left, target, path) || findPath(root.Right, target, path) {
        return true
    }

    *path = (*path)[:len(*path)-1]
    return false
}

