public class Solution {
    public TreeNode lowestCommonAncestorOfABst(TreeNode root, TreeNode p, TreeNode q) {
        List<TreeNode> pathToP = new List<TreeNode>();
        List<TreeNode> pathToQ = new List<TreeNode>();

        FindPath(root, p, pathToP);
        FindPath(root, q, pathToQ);

        TreeNode lca = null;
        int minLength = Math.Min(pathToP.Count, pathToQ.Count);

        for (int i = 0; i < minLength; i++) {
            if (pathToP[i] == pathToQ[i]) {
                lca = pathToP[i];
            } else {
                break;
            }
        }

        return lca;
    }

    private bool FindPath(TreeNode root, TreeNode target, List<TreeNode> path) {
        if (root == null) {
            return false;
        }

        path.Add(root);

        if (root == target) {
            return true;
        }

        if (FindPath(root.left, target, path) || FindPath(root.right, target, path)) {
            return true;
        }

        path.RemoveAt(path.Count - 1);
        return false;
    }
}

